  ('judicial-d35ec6db-moex-00287', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲、乙共同繼承父親現金新臺幣（下同）1000萬元，而甲生前曾向父親消費借貸500萬元，還沒 有償還，經計算甲僅得繼承父親遺產250萬元。其法律關係為何？', '["特留分扣減權", "特種贈與", "普通贈與", "債務之扣還"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00288', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '下列何者為憲法增修條文所明定之基本國策？', '["扶助弱勢政黨", "扶助人民興辦之中小型經濟事業", "保障身心障礙者之收入", "保障大陸地區人民政治參與"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00289', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '依憲法增修條文規定，教育、科學、文化之經費，應如何編列？', '["國民教育經費應優先編列", "基本教育經費應優先編列", "學行俱優無力升學之學生獎學金應優先編列", "邊遠及貧瘠地區之教育文化經費應優先編列"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00290', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '依憲法第8條及相關大法官解釋意旨，關於人身自由，下列敘述何者錯誤？', '["除現行犯之逮捕與拘禁外，僅限於警察機關始得依法定程序執行逮捕與拘禁", "憲法第8條第1項所稱之警察機關，並不限於組織法上形式意義之「警察」", "違警罰法之前數度遭大法官宣告違憲，主因就是該法諸多條文牴觸憲法第8條有關人身自由保障之規定", "憲法第8條第1項所稱之司法機關，包括檢察機關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00291', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '依據司法院釋字第573號解釋之意旨，關於憲法對宗教信仰自由之保障，下列敘述何者錯誤？', '["人民所從事之宗教行為與其內心宗教信念無法截然二分，均應受憲法絕對之保障", "宗教團體就其財產之處分，同時受憲法財產權與信仰自由之保障", "宗教性結社，就其內部組織結構、人事及財政管理應享有自主權", "國家對宗教應謹守中立及寬容原則，不得對特定之宗教加以獎勵或禁制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00292', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '關於原住民族工作權保障法規定，依政府採購法得標之廠商，於國內員工總人數逾100人者，應於履約期 間僱用原住民，其人數不得低於總人數百分之一，下列敘述何者錯誤？', '["此為立法者對原住民所為之優惠性差別待遇", "此規定將影響得標廠商之營業自由", "此規定符合憲法增修條文第10條保障原住民地位之精神", "此規定違反憲法第7條平等原則之要求"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00293', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '有關應考試權，下列敘述何者錯誤？', '["應考試權，係指具備一定資格之人民有報考國家所舉辦公務人員任用資格暨專門職業及技術人員執業資 格考試之權利", "依考試法舉行之考試，對於應考資格體格試驗，或檢覈經決定不及格者，得依法提起救濟", "因資格不符而遭否准參選之公職候選人，因選舉於訴訟期間已舉行完畢，已無救濟實益，故法院應裁定 駁回起訴", "受緩刑宣告者，緩刑期間不得參加公務員考試"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00294', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '關於憲法第21條規定之國民教育，下列敘述何者錯誤？', '["本條係規定人民有請求接受國民教育的權利", "國家依本條規定可制定法律強制人民接受國民義務教育", "人民受國民教育以外其他教育之受教權亦可從本條導出", "國民義務教育之內容得由法律形成之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00295', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '依司法院釋字第689號解釋意旨，社會秩序維護法對新聞採訪者之跟追行為有一定的限制，旨在衡平跟追 者的新聞採訪自由與被跟追者之何種自由？', '["結社自由", "言論自由", "遷徙自由", "一般行為自由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00296', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-3d2b73b6', 'sub-judicial-d35ec6db-07', NULL, 'single_choice', '下列何者最不屬於比例原則之內涵？', '["基本權干預之目的應該具體明確", "基本權干預的手段有助於目的達成", "採取較小侵害的干預手段", "手段所造成之損害應不大於其目的所擬維護之公共利益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "19ac2d85111a", "answer_pdf_sha1": "7a6ee01224e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0206", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
